mapper.select:
/* getWasnhdList */ SELECT
WA.EOASNKY as ROWKEY,
WA.EOASNKY,
WA.WAREKEY, MW.WHNAMLC, WA.DOCCATE, MD.DOCCTNM, WA.DOCTYPE, MD.DOCTYNM, WA.VOWNKEY, MVO.VONAMLC, WA.VEHICKY, MV.VHCFNAM, WA.DRVERNM, WA.ASNSTAT, MC.COMCDTX AS ASNSTNM, DATE_FORMAT(WA.ASNDATE,'%Y-%m-%d') AS ASNDATE, DATE_FORMAT(STR_TO_DATE(WA.ASNTIME,'%H%i%s'),'%H:%i:%s') AS ASNTIME, WA.RSNCODE, MR.RSNCDNM, WA.PARSNNM, WA.ASNPIYN, WA.ASNITYN, WA.ENTDATE, WA.ENTTIME, WA.PASTRKY, WA.HDSAVYN,
COUNT(1) AS ITEMCNT, SUM(WAI.SKUWEIG) AS TTLWEIG, SUM(WAI.ASNDQTY) AS TTLDQTY,
DATE_FORMAT(WA.CREDATE,'%Y-%m-%d') AS CREDATE, DATE_FORMAT(STR_TO_DATE(WA.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WA.CREUSER) AS CREUSER, DATE_FORMAT(WA.LMODATE,'%Y-%m-%d') as LMODATE, DATE_FORMAT(STR_TO_DATE(WA.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WA.LMOUSER) AS LMOUSER, WA.UPDTCHK FROM ${userData.schema}.WASNHD WA INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WA.WAREKEY AND MW.WHUSEYN = 'Y' LEFT JOIN ${userData.commonSchema}.MVOWMA MVO ON MVO.VOWNKEY = WA.VOWNKEY AND MVO.VOUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MVO.VOWNKEY = MV.VOWNKEY AND MV.VEHICKY = WA.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WA.ASNSTAT AND MC.COMCDKY = 'ASNSTAT' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WA.WAREKEY AND MD.DOCCATE = WA.DOCCATE AND MD.DOCTYPE = WA.DOCTYPE AND MD.DOUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WA.WAREKEY AND MR.DOCCATE = WA.DOCCATE AND MR.DOCTYPE = WA.DOCTYPE AND MR.RSNCODE = WA.RSNCODE AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.WASNIT WAI ON WAI.WAREKEY = WA.WAREKEY AND WAI.EOASNKY = WA.EOASNKY
AND WAI.COSTRKY IS NOT NULL AND WAI.COSTRIT IS NOT NULL
AND (WAI.COSTRKY IS NULL OR TRIM(WAI.COSTRKY) = '') AND (WAI.COSTRIT IS NULL OR TRIM(WAI.COSTRIT) = '')
AND WA.WAREKEY = #{param.warekey}
AND WA.EOASNKY LIKE CONCAT('%', #{param.eoasnky}, '%')
AND MV.VHCFNAM LIKE CONCAT('%', #{param.vhcfnam}, '%')
AND WAI.PURCNUM LIKE CONCAT('%', #{param.purcnum}, '%')
AND WAI.ORDERLN IN
#{orderln}
AND WAI.ORDERLN LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND DATE_FORMAT(STR_TO_DATE(WA.ASNDATE, '%Y%m%d'), '%Y-%m-%d') >= #{param.asndatefrom}
AND DATE_FORMAT(STR_TO_DATE(WA.ASNDATE, '%Y%m%d'), '%Y-%m-%d') <= #{param.asndateto}
AND WA.ASNPIYN = #{param.asnpiyn}
AND WA.ASNITYN = #{param.asnityn}
AND WA.ASNSTAT IN
#{asnstat}
AND WA.ASNSTAT IN ('NEW', 'ACONF','PCANCEL','PCONF')
AND WA.ASNITST IN
#{asnitst}
AND (SELECT COUNT(1) from WASNIT A WHERE A.EOASNKY = WA.EOASNKY and A.ASNITST = 'NEW') = 0
AND (SELECT COUNT(1) from WASNIT A WHERE A.EOASNKY = WA.EOASNKY and A.ASNITST = 'NEW') > 0
GROUP BY WA.EOASNKY, WA.WAREKEY, MW.WHNAMLC, WA.DOCCATE, MD.DOCCTNM, WA.DOCTYPE, MD.DOCTYNM, WA.VOWNKEY, MVO.VONAMLC, WA.VEHICKY, MV.VHCFNAM, WA.DRVERNM, WA.ASNSTAT, ASNSTNM, WA.ASNDATE, WA.ASNTIME, WA.RSNCODE, MR.RSNCDNM, WA.PARSNNM, WA.ASNPIYN, WA.ENTDATE, WA.ENTTIME, WA.CREDATE, WA.CREUSER, WA.LMODATE, WA.LMOTIME, WA.LMOUSER, WA.UPDTCHK ORDER BY WA.EOASNKY DESC, WA.ASNDATE DESC, WA.ASNTIME DESC

/* selectWasnitListWithoutTask */ SELECT
CONCAT(WAI.EOASNKY, WAI.EOASNIT) as ROWKEY,
WAI.EOASNKY, WAI.EOASNIT,
WAI.WAREKEY, MW.WHNAMLC, date_format(WAI.POSHPDT, '%Y-%m-%d') AS POSHPDT, DATE_FORMAT(STR_TO_DATE(WAI.POSHPTM,'%H%i%s'),'%H:%i:%s') as POSHPTM, WAI.POSHPDY, WAI.INVOICE, WAI.OWNERKY, WAI.OWNRNAM, WAI.ASNITST, MCO2.COMCDTX AS ASNITSN, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, ((SELECT count(1) FROM ${userData.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey}) - WAI.STLAYER + 1) AS VSLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.GROSSTH, WAI.SUOMKEY, MCO3.COMCDTX AS SUOMNAM, WAI.SKUSTRD, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, WAI.CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC AS RGORGNM, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC AS RGMODNM, WAI.DEMODNM, WAI.ULLOCKY, ML1.LOCANAM AS ULLOCNM, WAI.TOAREKY, MA.AREANAM AS TOARENM, WAI.TOLOCKY, ML2.LOCANAM AS TOLOCNM, WAI.TOLAYER, WAI.ITEMCOD, MCO4.COMCDTX AS ITCODNM, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, MCO1.COMCDTX AS SKUSTNM, WAI.SHPLIMT AS SHPLIMT, WAI.DELVDSR AS DELVDSR, WAI.RSNCODE, MRC.RSNCDNM AS RSNCDNM, MRC.RSCATE1, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, WAI.SERINUM, WAI.SAVEPOS, WAI.SCHDATE, WAI.MIXLOAD, WAI.DESTTRG, WAI.YARDTRG, WAI.INBDATE, WAI.INBVHNM, WAI.OUBVHNM, WAI.SHPDRNM, WAI.PRSALDT, WAI.CMPDATE, WAI.SHPPERS, WAI.OUBDATE, WAI.PREPRDE, WAI.ARVDATE, WAI.SHPODAT, WAI.TRSODAT, WAI.INDIMET, WAI.OUTDIMT, WAH.DOCCATE, WAH.DOCTYPE, WAI.BTRCATE, WAI.EQUIPKY, WAI.DEMDMAN, WAI.DEMDADR, WAI.DEMPOCD, WAI.DEMDTLN, MCO5.COMCDTX AS ADDCONM, BT.BTRCNAM,
MAX(DATE_FORMAT(WAI.CREDATE,'%Y%m%d')) as CREDATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.CRETIME,'%H%i%s'),'%H:%i:%s')) AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WAI.CREUSER) AS CREUSER, MAX(DATE_FORMAT(WAI.LMODATE,'%Y%m%d')) AS LMODATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.LMOTIME,'%H%i%s'),'%H:%i:%s')) AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WAI.LMOUSER) AS LMOUSER, MAX(WAI.UPDTCHK) AS UPDTCHK FROM ${userData.schema}.WASNIT WAI INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WAI.WAREKEY INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WAI.WAREKEY AND MA.AREAKEY = WAI.TOAREKY LEFT JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WAI.WAREKEY
AND ML1.LOCAKEY = WAI.ULLOCKY LEFT JOIN ${userData.schema}.MLOCMA ML2 ON ML1.WAREKEY = WAI.WAREKEY AND ML2.AREAKEY = MA.AREAKEY AND ML2.LOCAKEY = WAI.TOLOCKY LEFT JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = WAI.SKUGRKY INNER JOIN ${userData.schema}.WASNHD WAH ON WAH.EOASNKY = WAI.EOASNKY LEFT JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WAI.REGIORG LEFT JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WAI.REGIMOD INNER JOIN ${userData.schema}.MCODEM MCO1 ON MCO1.COMCDVL = WAI.SKUSTAT AND MCO1.COMCDKY = 'SKUSTAT' INNER JOIN ${userData.schema}.MCODEM MCO2 ON MCO2.COMCDVL = WAI.ASNITST AND MCO2.COMCDKY = 'ASNITST' INNER JOIN ${userData.schema}.MCODEM MCO3 ON MCO3.COMCDVL = WAI.SUOMKEY AND MCO3.COMCDKY = 'SUOMKEY' INNER JOIN ${userData.schema}.MCODEM MCO4 ON MCO4.COMCDVL = WAI.ITEMCOD AND MCO4.COMCDKY = 'ITEMCOD' INNER JOIN ${userData.schema}.BADDCO BA ON WAI.ADDCOKY = BA.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MCO5 ON BA.ADDSIKY = MCO5.COMCDVL AND MCO5.COMCDKY = 'ADDSIKY' AND MCO5.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MRC ON MRC.WAREKEY = WAH.WAREKEY AND MRC.WAREKEY = WAI.WAREKEY AND MRC.DOCCATE = WAH.DOCCATE AND MRC.DOCTYPE = WAH.DOCTYPE AND MRC.RSNCODE = WAI.RSNCODE LEFT JOIN ${userData.schema}.BTRCAT BT ON BT.BTRCATE = WAI.BTRCATE
AND WAI.WAREKEY = #{param.warekey}
AND WAI.EOASNKY = #{param.eoasnky}
AND WAI.ASNITST IN
#{asnitst}
GROUP BY WAI.EOASNKY, WAI.EOASNIT, WAI.WAREKEY, MW.WHNAMLC, WAI.POSHPDT, WAI.INVOICE, WAI.OWNERKY, WAI.OWNRNAM, WAI.ASNITST, MCO2.COMCDTX, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, VSLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.GROSSTH, WAI.SUOMKEY, MCO3.COMCDTX, WAI.SKUSTRD, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, WAI.CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC, WAI.DEMODNM, WAI.ULLOCKY, ML1.LOCANAM, WAI.TOAREKY, MA.AREANAM, WAI.TOLOCKY, ML2.LOCANAM, WAI.TOLAYER, WAI.ITEMCOD, MCO4.COMCDTX, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, MCO1.COMCDTX, WAI.SHPLIMT, WAI.DELVDSR, WAI.RSNCODE, MRC.RSNCDNM, MRC.RSCATE1, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, WAI.SERINUM, WAI.SAVEPOS, WAI.SCHDATE, WAI.MIXLOAD, WAI.DESTTRG, WAI.YARDTRG, WAI.INBDATE, WAI.INBVHNM, WAI.OUBVHNM, WAI.SHPDRNM, WAI.PRSALDT, WAI.CMPDATE, WAI.SHPPERS, WAI.OUBDATE, WAI.PREPRDE, WAI.ARVDATE, WAI.SHPODAT, WAI.TRSODAT, WAI.INDIMET, WAI.OUTDIMT, WAH.DOCCATE, WAH.DOCTYPE, WAI.EQUIPKY ORDER BY WAI.EOASNKY DESC, VSLAYER, WAI.STLAYER, WAI.EOASNIT

/* getWasnitList */ SELECT
CONCAT(WAI.EOASNKY, WAI.EOASNIT) as ROWKEY,
WAI.EOASNKY, WAI.EOASNIT,
WAI.WAREKEY, MW.WHNAMLC, DATE_FORMAT(WAI.POSHPDT,'%Y-%m-%d') AS POSHPDT, DATE_FORMAT(STR_TO_DATE(WAI.POSHPTM,'%H%i%s'),'%H:%i:%s') as POSHPTM, WAI.POSHPDY, WAI.INVOICE, WAI.OWNERKY, WAI.OWNRNAM, WAI.ASNITST, MCO2.COMCDTX AS ASNITSN, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, ((SELECT count(1) - WAI.STLAYER + 1 FROM ${userData.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey})) AS VSLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.GROSSTH, WAI.SUOMKEY, MCO3.COMCDTX AS SUOMNAM, WAI.SKUSTRD, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, WAI.CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC AS RGORGNM, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC AS RGMODNM, WAI.DEMODNM, WAI.DEMDMAN, WAI.DEMDADR, WAI.DEMPOCD, WAI.DEMDTLN, WAI.ULLOCKY, ML1.LOCANAM AS ULLOCNM, WAI.TOAREKY, MA.AREANAM AS TOARENM, WAI.TOLOCKY, ML2.LOCANAM AS TOLOCNM, WAI.TOLAYER, WAI.ITEMCOD, MCO4.COMCDTX AS ITCODNM, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, MCO1.COMCDTX AS SKUSTNM, DATE_FORMAT(WAI.SHPLIMT,'%Y-%m-%d') AS SHPLIMT, DATE_FORMAT(WAI.DELVDSR,'%Y-%m-%d') AS DELVDSR, WAI.RSNCODE, MRC.RSNCDNM AS RSNCDNM, MRC.RSCATE1, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, WAI.SERINUM, WAI.SAVEPOS, WAI.SCHDATE, WAI.MIXLOAD, WAI.DESTTRG, WAI.YARDTRG, WAI.INBDATE, WAI.INBVHNM, WAI.OUBVHNM, WAI.SHPDRNM, WAI.PRSALDT, WAI.CMPDATE, WAI.SHPPERS, WAI.OUBDATE, WAI.PREPRDE, WAI.ARVDATE, WAI.SHPODAT, WAI.TRSODAT, WAI.INDIMET, WAI.OUTDIMT, WAH.DOCCATE, WAH.DOCTYPE, MDO.DOCCTNM, MDO.DOCTYNM, WAI.BTRCATE, BT.BTRCNAM, WAI.FNCUSKY, WAI.EQUIPKY, MCO5.COMCDTX AS ADDCONM,
MAX(DATE_FORMAT(WAI.CREDATE,'%Y%m%d')) as CREDATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.CRETIME,'%H%i%s'),'%H:%i:%s')) AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WAI.CREUSER) AS CREUSER, MAX(DATE_FORMAT(WAI.LMODATE,'%Y%m%d')) AS LMODATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.LMOTIME,'%H%i%s'),'%H:%i:%s')) AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WAI.LMOUSER) AS LMOUSER, MAX(WAI.UPDTCHK) AS UPDTCHK FROM ${userData.schema}.WASNIT WAI INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WAI.WAREKEY LEFT JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WAI.WAREKEY AND MA.AREAKEY = WAI.TOAREKY LEFT JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WAI.WAREKEY AND ML1.LOCAKEY = WAI.ULLOCKY LEFT JOIN ${userData.schema}.MLOCMA ML2 ON ML1.WAREKEY = WAI.WAREKEY AND ML2.AREAKEY = MA.AREAKEY AND ML2.LOCAKEY = WAI.TOLOCKY LEFT JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = WAI.SKUGRKY INNER JOIN ${userData.schema}.WASNHD WAH ON WAH.EOASNKY = WAI.EOASNKY LEFT JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WAI.REGIORG LEFT JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WAI.REGIMOD INNER JOIN ${userData.schema}.MCODEM MCO1 ON MCO1.COMCDVL = WAI.SKUSTAT AND MCO1.COMCDKY = 'SKUSTAT' INNER JOIN ${userData.schema}.MCODEM MCO2 ON MCO2.COMCDVL = WAI.ASNITST AND MCO2.COMCDKY = 'ASNITST' INNER JOIN ${userData.schema}.MCODEM MCO3 ON MCO3.COMCDVL = WAI.SUOMKEY AND MCO3.COMCDKY = 'SUOMKEY' INNER JOIN ${userData.schema}.MCODEM MCO4 ON MCO4.COMCDVL = WAI.ITEMCOD AND MCO4.COMCDKY = 'ITEMCOD' INNER JOIN ${userData.schema}.MDOCMA MDO ON MDO.DOCCATE = WAI.DOCCATE AND MDO.DOCTYPE = WAI.DOCTYPE LEFT JOIN ${userData.schema}.MRSCMA MRC ON MRC.WAREKEY = WAH.WAREKEY AND MRC.WAREKEY = WAI.WAREKEY AND MRC.DOCCATE = WAH.DOCCATE AND MRC.DOCTYPE = WAH.DOCTYPE AND MRC.RSNCODE = WAI.RSNCODE LEFT JOIN ${userData.schema}.BTRCAT BT ON BT.BTRCATE = WAI.BTRCATE INNER JOIN ${userData.schema}.BADDCO BA ON WAI.ADDCOKY = BA.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MCO5 ON BA.ADDSIKY = MCO5.COMCDVL AND MCO5.COMCDKY = 'ADDSIKY' AND MCO5.COUSEYN = 'Y'
AND WAI.WAREKEY = #{param.warekey}
AND WAI.EOASNKY = #{param.eoasnky}
AND WAI.ASNITST IN
#{asnitst}
GROUP BY WAI.EOASNKY, WAI.EOASNIT, WAI.WAREKEY, MW.WHNAMLC, WAI.POSHPDT, WAI.INVOICE, WAI.OWNERKY, WAI.OWNRNAM, WAI.ASNITST, MCO2.COMCDTX, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, VSLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.GROSSTH, WAI.SUOMKEY, MCO3.COMCDTX, WAI.SKUSTRD, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, WAI.CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC, WAI.DEMODNM, WAI.ULLOCKY, ML1.LOCANAM, WAI.TOAREKY, MA.AREANAM, WAI.TOLOCKY, ML2.LOCANAM, WAI.TOLAYER, WAI.ITEMCOD, MCO4.COMCDTX, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, MCO1.COMCDTX, WAI.SHPLIMT, WAI.DELVDSR, WAI.RSNCODE, MRC.RSNCDNM, MRC.RSCATE1, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, WAI.SERINUM, WAI.SAVEPOS, WAI.SCHDATE, WAI.MIXLOAD, WAI.DESTTRG, WAI.YARDTRG, WAI.INBDATE, WAI.INBVHNM, WAI.OUBVHNM, WAI.SHPDRNM, WAI.PRSALDT, WAI.CMPDATE, WAI.SHPPERS, WAI.OUBDATE, WAI.PREPRDE, WAI.ARVDATE, WAI.SHPODAT, WAI.TRSODAT, WAI.INDIMET, WAI.OUTDIMT, WAH.DOCCATE, WAH.DOCTYPE ORDER BY WAI.STLAYER DESC

/* getDoe024WasnitList */ WITH FILTER_OWNER_CUST AS ( SELECT CASE WHEN WAI.OWNERKY IS NULL OR TRIM(WAI.OWNERKY) = '' THEN ( SELECT CUSTKEY FROM ${userData.schema}.MCUSMA WHERE CUNAMLC = WAI.OWNRNAM ORDER BY CUSTKEY LIMIT 1 ) ELSE WAI.OWNERKY END AS OWNERKY , OWNRNAM , CASE WHEN WAI.CUSTCOD IS NULL OR TRIM(WAI.CUSTCOD) = '' THEN ( SELECT CUSTKEY FROM ${userData.schema}.MCUSMA WHERE CUNAMLC = WAI.CUSTNAM ORDER BY CUSTKEY LIMIT 1 ) ELSE WAI.CUSTCOD END AS CUSTCOD , CUSTNAM FROM ${userData.schema}.WASNIT WAI WHERE WAI.WAREKEY = #{param.warekey} AND WAI.EOASNKY = #{param.eoasnky} ) SELECT
CONCAT(WAI.EOASNKY, WAI.EOASNIT) as ROWKEY,
WAI.EOASNKY, WAI.EOASNIT,
WAI.WAREKEY, MW.WHNAMLC, DATE_FORMAT(WAI.POSHPDT,'%Y-%m-%d') AS POSHPDT, WAI.INVOICE, CASE WHEN WAI.OWNERKY IS NULL OR TRIM(WAI.OWNERKY) = '' THEN ( SELECT CUSTKEY FROM ${userData.schema}.MCUSMA WHERE CUNAMLC = WAI.OWNRNAM ORDER BY CUSTKEY LIMIT 1 ) ELSE WAI.OWNERKY END AS OWNERKY, WAI.OWNRNAM, WAI.ASNITST, (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ASNITST' AND COMCDVL = WAI.ASNITST AND COUSEYN = 'Y') AS ASNITSN, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, ((SELECT count(1) - WAI.STLAYER + 1 FROM ${userData.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey})) AS VSLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.GROSSTH, WAI.SUOMKEY, (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'SUOMKEY' AND COMCDVL = WAI.SUOMKEY AND COUSEYN = 'Y') AS SUOMNAM, WAI.SKUSTRD, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, CASE WHEN WAI.CUSTCOD IS NULL OR TRIM(WAI.CUSTCOD) = '' THEN (SELECT CUSTKEY FROM ${userData.schema}.MCUSMA WHERE CUNAMLC = WAI.CUSTNAM ORDER BY CUSTKEY LIMIT 1) ELSE WAI.CUSTCOD END AS CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC AS RGORGNM, IFNULL(MDE.DESTKEY,'') AS DESTORG, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC AS RGMODNM, IFNULL(MDE.DESTKEY,'') AS DESTMOD, WAI.DEMODNM, CASE WHEN WAI.DEMDADR IS NOT NULL AND TRIM(WAI.DEMDADR) != '' THEN WAI.DEMDADR WHEN MDE.DESTKEY IS NULL AND TRIM(MDE.DESTKEY) = '' THEN (SELECT DESADDR FROM ${userData.schema}.MDESMA WHERE DENAMLC = WAI.DEMODNM ORDER BY REGIKEY, CUSTKEY, DESTKEY LIMIT 1) ELSE MDE.DESADDR END AS DEMDADR, CASE WHEN WAI.DEMDMAN IS NOT NULL AND TRIM(WAI.DEMDMAN) != '' THEN WAI.DEMDMAN WHEN MDE.DESTKEY IS NULL AND TRIM(MDE.DESTKEY) = '' THEN (SELECT DEMANNM FROM ${userData.schema}.MDESMA WHERE DENAMLC = WAI.DEMODNM ORDER BY REGIKEY, CUSTKEY, DESTKEY LIMIT 1) ELSE MDE.DEMANNM END AS DEMDMAN, CASE WHEN WAI.DEMDTLN IS NOT NULL AND TRIM(WAI.DEMDTLN) != '' THEN WAI.DEMDTLN WHEN MDE.DESTKEY IS NULL AND TRIM(MDE.DESTKEY) = '' THEN (SELECT DESTELN FROM ${userData.schema}.MDESMA WHERE DENAMLC = WAI.DEMODNM ORDER BY REGIKEY, CUSTKEY, DESTKEY LIMIT 1) ELSE MDE.DESTELN END AS DEMDTLN, CASE WHEN WAI.DEMPOCD IS NOT NULL AND TRIM(WAI.DEMPOCD) != '' THEN WAI.DEMPOCD WHEN MDE.DESTKEY IS NULL AND TRIM(MDE.DESTKEY) = '' THEN (SELECT DEPOSCD FROM ${userData.schema}.MDESMA WHERE DENAMLC = WAI.DEMODNM ORDER BY REGIKEY, CUSTKEY, DESTKEY LIMIT 1) ELSE MDE.DEPOSCD END AS DEMPOCD, WAI.ULLOCKY, ML1.LOCANAM AS ULLOCNM, WAI.TOAREKY, MA.AREANAM AS TOARENM, WAI.TOLOCKY, ML2.LOCANAM AS TOLOCNM, WAI.TOLAYER, WAI.ITEMCOD, (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ITEMCOD' AND COMCDVL = WAI.ITEMCOD AND COUSEYN = 'Y') AS ITCODNM, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, (SELECT COMCDTX FROM DO_DY.MCODEM WHERE COMCDKY = 'SKUSTAT' AND COMCDVL = WAI.SKUSTAT AND COUSEYN = 'Y') AS SKUSTNM, DATE_FORMAT(WAI.SHPLIMT,'%Y-%m-%d') AS SHPLIMT, DATE_FORMAT(WAI.DELVDSR,'%Y-%m-%d') AS DELVDSR, WAI.RSNCODE, MRC.RSNCDNM AS RSNCDNM, MRC.RSCATE1, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, WAI.SERINUM, WAI.SAVEPOS, WAI.SCHDATE, WAI.MIXLOAD, WAI.DESTTRG, WAI.YARDTRG, WAI.INBDATE, WAI.INBVHNM, WAI.OUBVHNM, WAI.SHPDRNM, WAI.PRSALDT, WAI.CMPDATE, WAI.SHPPERS, WAI.OUBDATE, WAI.PREPRDE, WAI.ARVDATE, WAI.SHPODAT, WAI.TRSODAT, WAI.INDIMET, WAI.OUTDIMT, WAH.DOCCATE, WAH.DOCTYPE, MDO.DOCCTNM, MDO.DOCTYNM, WAI.BTRCATE, BT.BTRCNAM, WAI.FNCUSKY, WAI.EQUIPKY, (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = BA.ADDSIKY AND COUSEYN = 'Y') AS ADDCONM, IF(WAI.ASNITST = 'NEW', 'N', 'Y') as ASNCFYN, WAH.ASNITYN,
MAX(DATE_FORMAT(WAI.CREDATE,'%Y%m%d')) as CREDATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.CRETIME,'%H%i%s'),'%H:%i:%s')) AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WAI.CREUSER) AS CREUSER, MAX(DATE_FORMAT(WAI.LMODATE,'%Y%m%d')) AS LMODATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.LMOTIME,'%H%i%s'),'%H:%i:%s')) AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WAI.LMOUSER) AS LMOUSER, MAX(WAI.UPDTCHK) AS UPDTCHK FROM ${userData.schema}.WASNIT WAI INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WAI.WAREKEY LEFT JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WAI.WAREKEY AND MA.AREAKEY = WAI.TOAREKY LEFT JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WAI.WAREKEY AND ML1.AREAKEY = WAI.TOAREKY AND ML1.LOCAKEY = WAI.ULLOCKY LEFT JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WAI.WAREKEY AND ML2.AREAKEY = WAI.TOAREKY AND ML2.LOCAKEY = WAI.TOLOCKY INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = WAI.SKUGRKY INNER JOIN ${userData.schema}.WASNHD WAH ON WAH.EOASNKY = WAI.EOASNKY LEFT JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WAI.REGIORG LEFT JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WAI.REGIMOD INNER JOIN ${userData.schema}.MDOCMA MDO ON MDO.WAREKEY = WAI.WAREKEY AND MDO.DOCCATE = WAI.DOCCATE AND MDO.DOCTYPE = WAI.DOCTYPE LEFT JOIN ${userData.schema}.MRSCMA MRC ON MRC.WAREKEY = WAH.WAREKEY AND MRC.WAREKEY = WAI.WAREKEY AND MRC.DOCCATE = WAH.DOCCATE AND MRC.DOCTYPE = WAH.DOCTYPE AND MRC.RSNCODE = WAI.RSNCODE LEFT JOIN ${userData.schema}.BTRCAT BT ON BT.BTRCATE = WAI.BTRCATE INNER JOIN ${userData.schema}.BADDCO BA ON WAI.ADDCOKY = BA.ADDCOKY LEFT JOIN FILTER_OWNER_CUST FOC ON FOC.OWNRNAM = WAI.OWNRNAM LEFT JOIN ${userData.schema}.MDESMA MDE ON MDE.CUSTKEY = FOC.OWNERKY AND MDE.REGIKEY = WAI.REGIMOD AND MDE.DENAMLC = WAI.DEMODNM
AND WAI.WAREKEY = #{param.warekey}
AND WAI.EOASNKY = #{param.eoasnky}
AND WAI.ASNITST IN
#{asnitst}
GROUP BY WAI.EOASNKY, WAI.EOASNIT, WAI.WAREKEY, MW.WHNAMLC, WAI.POSHPDT, WAI.INVOICE, WAI.OWNERKY, WAI.OWNRNAM, WAI.ASNITST, ASNITSN, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, VSLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.GROSSTH, WAI.SUOMKEY, SUOMNAM, WAI.SKUSTRD, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, WAI.CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC, WAI.DEMODNM, WAI.ULLOCKY, ML1.LOCANAM, WAI.TOAREKY, MA.AREANAM, WAI.TOLOCKY, ML2.LOCANAM, WAI.TOLAYER, WAI.ITEMCOD, ITCODNM, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, SKUSTNM, WAI.SHPLIMT, WAI.DELVDSR, WAI.RSNCODE, MRC.RSNCDNM, MRC.RSCATE1, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, WAI.SERINUM, WAI.SAVEPOS, WAI.SCHDATE, WAI.MIXLOAD, WAI.DESTTRG, WAI.YARDTRG, WAI.INBDATE, WAI.INBVHNM, WAI.OUBVHNM, WAI.SHPDRNM, WAI.PRSALDT, WAI.CMPDATE, WAI.SHPPERS, WAI.OUBDATE, WAI.PREPRDE, WAI.ARVDATE, WAI.SHPODAT, WAI.TRSODAT, WAI.INDIMET, WAI.OUTDIMT, WAH.DOCCATE, WAH.DOCTYPE, WAI.FNCUSKY, WAI.EQUIPKY, ADDCONM ORDER BY WAI.EOASNKY DESC, VSLAYER, WAI.STLAYER, WAI.EOASNIT

/* selectPlainWasnhd */ SELECT
WA.EOASNKY,
WA.WAREKEY, WA.DOCCATE, WA.DOCTYPE, WA.VOWNKEY, WA.VEHICKY, WA.VHCFNAM, WA.DRVERNM, WA.ASNSTAT, WA.ASNDATE, WA.ASNTIME, WA.ENTDATE, WA.ENTTIME, WA.RSNCODE, WA.PARSNNM, WA.ASNPIYN, WA.ASNITYN, WA.PASTRKY,
WA.CREDATE, WA.CRETIME, WA.CREUSER, WA.LMODATE, WA.LMOTIME, WA.LMOUSER, WA.UPDTCHK FROM ${userData.schema}.WASNHD WA WHERE WA.EOASNKY = #{param.eoasnky}
AND WA.WAREKEY = #{param.warekey}
AND WA.ASNSTAT = #{param.asnstat}

