AND WA.ASNITST in
#{asnitst}

/* selectWasnitKeyAndItem */ SELECT
WA.EOASNKY, WA.EOASNIT,
WA.WAREKEY, WA.POSHPDT, WA.POSHPTM, WA.POSHPDY, WA.INVOICE, WA.DOCCATE, WA.DOCTYPE, WA.BTRCATE, WA.OWNERKY, WA.OWNRNAM, WA.ASNITST, WA.SKUGRKY, WA.SKUMKEY, WA.SKUDESC, WA.STLAYER, WA.SKUWEIG, WA.SKUWIDT, WA.SKULENG, WA.SKUTHIC, WA.GROSSWD, WA.GROSSLN, WA.GROSSWG, WA.GROSSTH, WA.SKUSTRD, WA.ULLOCKY, WA.EQUIPKY, WA.TOAREKY, WA.TOLOCKY, WA.TOLAYER, WA.SUOMKEY, WA.ADDCOKY, WA.ASNDQTY, WA.RCHSQTY, WA.CUSTCOD, WA.CUSTNAM, WA.FNCUSKY, WA.FCNAMLC, WA.REGIORG, WA.REGIMOD, WA.DESTORG, WA.DEORGNM, WA.DESTMOD, WA.DEMODNM, WA.DEMODYN, WA.DEMDMAN, WA.DEMDADR, WA.DEMPOCD, WA.DEMDTLN, WA.ITEMCOD, WA.PURCNUM, WA.ORDERLN, WA.BTRFSTC, WA.STLOTNB, WA.SHPLIMT, WA.STKMEMO, WA.DELVDSR, WA.RESTKYN, WA.SKUSTAT, WA.RSNCODE, WA.PARSNNM, WA.COSTRKY, WA.COSTRIT, WA.SERINUM, WA.SAVEPOS, WA.SCHDATE, WA.MIXLOAD, WA.DESTTRG, WA.YARDTRG, WA.INBDATE, WA.INBVHNM, WA.OUBVHNM, WA.SHPDRNM, WA.PRSALDT, WA.CMPDATE, WA.SHPPERS, WA.OUBDATE, WA.PREPRDE, WA.ARVDATE, WA.SHPODAT, WA.TRSODAT, WA.INDIMET, WA.OUTDIMT,
WA.CREDATE, WA.CRETIME, WA.CREUSER, WA.LMODATE, WA.LMOTIME, WA.LMOUSER, WA.UPDTCHK FROM ${userData.schema}.WASNIT WA WHERE WA.WAREKEY = #{param.warekey} AND WA.EOASNKY = #{param.eoasnky}
AND WA.ASNITST in
#{asnitst}

/* selectWasnitKeyAndItemNotCancel */ SELECT
WA.EOASNKY, WA.EOASNIT,
WA.WAREKEY, WA.ASNITST, WA.SKUMKEY, WA.ULLOCKY, WA.COSTRKY, WA.COSTRIT, WA.UPDTCHK FROM ${userData.schema}.WASNIT WA WHERE WA.WAREKEY = #{param.warekey} AND WA.EOASNKY = #{param.eoasnky}
AND WA.ASNITST in
#{asnitst}
AND WA.ASNITST != 'CANCEL'

