/* updateWasnitToTopLayer */
UPDATE ${userData.schema}.WASNIT AS IT
SET
	IT.STLAYER = #{param.stlayer},
	IT.LMODATE = date_format(now(), '%Y%m%d'),
	IT.LMOTIME = date_format(now(), '%H%i%s'),
	IT.LMOUSER = #{userData.useract}
WHERE
	IT.EOASNKY = #{param.eoasnky}
	AND IT.WAREKEY = #{param.warekey}
	AND IT.STLAYER = (SELECT COUNT(1) FROM ${userData.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey})

/* updateWasnitSwapLayer */
UPDATE ${userData.schema}.WASNIT
SET
	STLAYER = (SELECT COUNT(1) FROM ${userData.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey}),
	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract},
	UPDTCHK = UPDTCHK + 1
WHERE
	EOASNKY = #{param.eoasnky}
	AND EOASNIT = #{param.eoasnit}
	AND WAREKEY = #{param.warekey}

/* updateDoe024WasnhdStatus */ UPDATE ${userData.schema}.WASNHD SET ASNSTAT = #{status}, HDSAVYN = #{param.hdsavyn},
RSNCODE = #{param.rsncode},
PARSNNM = #{param.parsnnm},
ASNITYN = #{param.asnityn},
LMODATE = date_format(now(), '%Y%m%d'), LMOTIME = date_format(now(), '%H%i%s'), LMOUSER = #{userData.useract}, UPDTCHK = UPDTCHK + 1 WHERE WAREKEY = #{param.warekey} AND EOASNKY = #{param.eoasnky}

/* updateWasnhdStauts */ UPDATE ${userData.schema}.WASNHD SET ASNSTAT = #{status},
RSNCODE = #{param.rsncode},
PARSNNM = #{param.rsncdnm},
PARSNNM = #{param.parsnnm},
ASNITYN = #{param.asnityn},
LMODATE = date_format(now(), '%Y%m%d'), LMOTIME = date_format(now(), '%H%i%s'), LMOUSER = #{userData.useract}, UPDTCHK = UPDTCHK + 1 WHERE WAREKEY = #{param.warekey} AND EOASNKY = #{param.eoasnky}

/* updateHeadAsnstatDoe027 */
UPDATE ${userData.schema}.WASNHD
SET ASNSTAT = #{param.asnstat},
	RSNCODE = #{param.rsncode},
	PARSNNM = IFNULL(#{param.parsnnm},''),
	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract},
	UPDTCHK = #{param.updtchk} + 1
WHERE
	WAREKEY = #{param.warekey}
	AND EOASNKY = #{param.eoasnky}
	AND UPDTCHK = #{param.updtchk}

