/* updateOstrhdStatus */
UPDATE ${userData.schema}.OSTRHD
SET
	STRSTAT = #{status},

	RSNCODE = #{param.rsncode},


	PARSNNM = #{param.parsnnm},

	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract}
WHERE
	WAREKEY = #{param.warekey}
	AND COSTRKY = #{param.costrky}

/* updateOstritStatus */

UPDATE ${userData.schema}.OSTRIT
SET
	STRITST = #{status},

	RSNCODE = #{data.rsncode},


	PARSNNM = #{data.parsnnm},


	STRCQTY = #{data.strcqty},

	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract}
WHERE
	WAREKEY = #{data.warekey}
	AND COSTRKY = #{data.costrky}
	AND COSTRIT = #{data.costrit}

	AND STRITST != 'CANCEL'

/* updateWasnhdFlagForInspectionTarget */

UPDATE ${userData.schema}.WASNHD
SET
	ASNITYN = #{data.asnityn},
	ENTDATE = IF(ISNULL(#{data.entdate}) OR TRIM(#{data.entdate}) = '', date_format(now(), '%Y%m%d'), date_format(#{data.entdate}, '%Y%m%d')),
	ENTTIME =  IF(ISNULL(#{data.enttime}) OR TRIM(#{data.enttime}) = '', date_format(now(), '%H%i%s'), date_format(STR_TO_DATE(#{data.enttime}, '%H%i%s'), '%H%i%s')),
	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract}
WHERE
	WAREKEY = #{data.warekey}
	AND EOASNKY = #{data.eoasnky}

mapper.select:
/* getDoe033HeadList */ SELECT
WA.EOASNKY as ROWKEY,
WA.EOASNKY, WT.RCVDCKY,
WA.WAREKEY, WT.TASKOKY, MW.WHNAMLC, WA.DOCCATE, MD.DOCCTNM, WA.DOCTYPE, MD.DOCTYNM, WA.VOWNKEY, MVO.VONAMLC, WA.VEHICKY, MV.VHCFNAM, WA.DRVERNM, WA.ASNSTAT, WT.EQUIPKY, MEQ.EQUINAM, MEQ.AREAKEY, MA.AREANAM, IFNULL(MAX(WT.TASKSTS), WA.ASNSTAT) as ASNSTAT, IFNULL (MAX(MC2.COMCDTX), MC.COMCDTX) as ASNSTNM, DATE_FORMAT(WA.ASNDATE,'%Y-%m-%d') AS ASNDATE, DATE_FORMAT(STR_TO_DATE(WA.ASNTIME,'%H%i%s'),'%H:%i:%s') AS ASNTIME, WA.RSNCODE, MR.RSNCDNM, WA.PARSNNM, WA.ASNPIYN,
COUNT(1) AS ITEMCNT, SUM(WAI.SKUWEIG) AS TTLWEIG, SUM(WAI.ASNDQTY) AS TTLDQTY,
DATE_FORMAT(WA.CREDATE,'%Y-%m-%d') AS CREDATE, DATE_FORMAT(STR_TO_DATE(WA.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WA.CREUSER) AS CREUSER, DATE_FORMAT(WA.LMODATE,'%Y-%m-%d') as LMODATE, DATE_FORMAT(STR_TO_DATE(WA.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WA.LMOUSER) AS LMOUSER, WA.UPDTCHK FROM ${userData.schema}.WASNHD WA INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WA.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVOWMA MVO ON MVO.VOWNKEY = WA.VOWNKEY AND MVO.VOUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MVO.VOWNKEY = MV.VOWNKEY AND MV.VEHICKY = WA.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WA.ASNSTAT AND MC.COMCDKY = 'ASNSTAT' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WA.WAREKEY AND MD.DOCCATE = WA.DOCCATE AND MD.DOCTYPE = WA.DOCTYPE AND MD.DOUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WA.WAREKEY AND MR.DOCCATE = WA.DOCCATE AND MR.DOCTYPE = WA.DOCTYPE AND MR.RSNCODE = WA.RSNCODE AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.WASNIT WAI ON WAI.WAREKEY = WA.WAREKEY AND WAI.EOASNKY = WA.EOASNKY INNER JOIN ${userData.schema}.WTAKIT WT ON WT.EOASNKY = WAI.EOASNKY AND WT.EOASNIT = WAI.EOASNIT AND WT.WAREKEY = WAI.WAREKEY INNER JOIN ${userData.schema}.WRCVIT WR ON WR.RCVDCKY = WT.RCVDCKY AND WR.RCVDCIT = WT.RCVDCIT LEFT JOIN ${userData.schema}.MCODEM MC2 ON MC2.COMCDVL = WT.TASKSTS AND MC2.COMCDKY = 'TASKSTS' AND MC2.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MEQUMA MEQ ON MEQ.WAREKEY = WT.WAREKEY AND MEQ.AREAKEY = WT.TOAREKY AND MEQ.EQUIPKY = WT.EQUIPKY AND MEQ.EQUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = MEQ.WAREKEY AND MA.AREAKEY = MEQ.AREAKEY
AND WA.WAREKEY = #{param.warekey}
AND WA.ASNSTAT = #{param.asnstat}
AND WA.EOASNKY LIKE CONCAT('%',#{param.eoasnky},'%')
AND WA.VHCFNAM LIKE CONCAT ('%', #{param.vhcfnam},'%')
AND WT.TASKOKY LIKE CONCAT('%',#{param.taskoky},'%')
AND MV.VHCFNAM LIKE CONCAT('%',#{param.vhcfnam},'%')
AND DATE_FORMAT(STR_TO_DATE(WA.ASNDATE, '%Y%m%d'), '%Y-%m-%d') >= #{param.asndatefrom}
AND DATE_FORMAT(STR_TO_DATE(WA.ASNDATE, '%Y%m%d'), '%Y-%m-%d') <= #{param.asndateto}
AND WA.ASNPIYN = #{param.asnpiyn}
AND WA.ASNSTAT IN
#{asnstat}
AND WAI.ASNITST = #{param.asnitst}
AND WT.EQUIPKY = #{param.equipky}
AND (WT.TASKSTS IS NULL OR WT.TASKSTS NOT IN ('OPERCMP', 'CMP')) AND WR.RCVITST != 'CANCEL'
GROUP BY WA.WAREKEY, MW.WHNAMLC, WA.DOCCATE, MD.DOCCTNM, WT.TASKOKY, WA.DOCTYPE, MD.DOCTYNM, WA.VOWNKEY, MVO.VONAMLC, WT.EQUIPKY, MEQ.EQUINAM, MEQ.AREAKEY, MA.AREANAM, WA.VEHICKY, MV.VHCFNAM, WA.DRVERNM, WA.ASNDATE, WA.ASNTIME, WA.RSNCODE, MR.RSNCDNM, WA.PARSNNM, WA.ASNPIYN, CREDATE, CREUSER, LMODATE, LMOTIME, LMOUSER, WA.UPDTCHK ORDER BY WT.TASKOKY DESC, WA.EOASNKY DESC

/* getDoe033ItemList */ SELECT
CONCAT(WAI.EOASNKY, WAI.EOASNIT) as ROWKEY,
WAI.EOASNKY, WAI.EOASNIT,
WRC.RCVDCKY, WRC.RCVDCIT, WAI.WAREKEY, MW.WHNAMLC, DATE_FORMAT(WAI.POSHPDT, '%Y-%m-%d') AS POSHPDT, WAI.INVOICE, WT.TASKOKY, WT.TASKOIT, WAI.OWNERKY, WAI.OWNRNAM, IFNULL(WT.TASKSTS, WAI.ASNITST) as ASNITST, IFNULL(WST.LOLAYER, 0) as LOLAYER, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, ((SELECT count(1) FROM ${userData.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey}) - WAI.STLAYER + 1) AS VSLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.GROSSTH, WAI.SUOMKEY, WAI.SKUSTRD, WAI.ULLOCKY, WT.TOAREKY, MA.AREANAM , WT.TOLOCKY, ML.LOCANAM, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, WAI.CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC AS RGORGNM, WAI.DESTORG, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC AS RGMODNM, WAI.DESTMOD, WAI.DEMODNM, WAI.DEMDMAN, WAI.DEMDADR, WAI.DEMPOCD, WAI.DEMDTLN, WAI.ITEMCOD, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, MG.GRPKYNM, BTR.BTRCNAM, DATE_FORMAT(WAI.SHPLIMT, '%Y-%m-%d') AS SHPLIMT, DATE_FORMAT(WAI.DELVDSR, '%Y-%m-%d') AS DELVDSR, WAI.RSNCODE, MRC.RSNCDNM AS RSNCDNM, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, WAI.BTRCATE, WAI.BTRFSTC, WAI.POSHPTM, WAI.POSHPDY, WAI.EQUIPKY, WAI.FNCUSKY, WAI.STKMEMO,
MAX(DATE_FORMAT(WAI.CREDATE,'%Y-%m-%d')) as CREDATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.CRETIME,'%H%i%s'),'%H:%i:%s')) AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WAI.CREUSER) AS CREUSER, MAX(DATE_FORMAT(WAI.LMODATE,'%Y-%m-%d')) as LMODATE, MAX(DATE_FORMAT(STR_TO_DATE(WAI.LMOTIME,'%H%i%s'),'%H:%i:%s')) AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WAI.LMOUSER) AS LMOUSER, WT.UPDTCHK , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ITEMCOD' AND COMCDVL = WAI.ITEMCOD AND COUSEYN = 'Y') AS ITCODNM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'SUOMKEY' AND COMCDVL = WAI.SUOMKEY AND COUSEYN = 'Y') AS SUOMNAM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'TASKSTS' AND COMCDVL = WT.TASKSTS AND COUSEYN = 'Y') AS TASKSTSNM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = BA.ADDSIKY AND COUSEYN = 'Y') AS ADDCONM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'SKUSTAT' AND COMCDVL = WAI.SKUSTAT AND COUSEYN = 'Y') AS SKUSTNM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'TASKSTS' AND COMCDVL = WT.TASKSTS AND COUSEYN = 'Y') AS ASNITSN FROM ${userData.schema}.WASNIT WAI INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WAI.WAREKEY INNER JOIN ${userData.schema}.WASNHD WAH ON WAH.EOASNKY = WAI.EOASNKY LEFT JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WAI.REGIORG LEFT JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WAI.REGIMOD LEFT JOIN ${userData.schema}.MRSCMA MRC ON MRC.WAREKEY = WAH.WAREKEY AND MRC.WAREKEY = WAI.WAREKEY AND MRC.DOCCATE = WAH.DOCCATE AND MRC.DOCTYPE = WAH.DOCTYPE AND MRC.RSNCODE = WAI.RSNCODE INNER JOIN ${userData.schema}.WTAKIT WT ON WT.EOASNKY = WAI.EOASNKY AND WT.EOASNIT = WAI.EOASNIT AND WT.WAREKEY = WAI.WAREKEY INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WT.WAREKEY AND MA.AREAKEY = WT.TOAREKY INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = WT.WAREKEY AND ML.AREAKEY = WT.TOAREKY AND ML.LOCAKEY = WT.TOLOCKY INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = WAI.SKUGRKY INNER JOIN ${userData.schema}.BTRCAT BTR ON BTR.BTRCATE = WAI.BTRCATE INNER JOIN ${userData.schema}.WRCVIT WRC ON WRC.EOASNKY = WAI.EOASNKY AND WRC.EOASNIT = WAI.EOASNIT LEFT JOIN ${userData.schema}.WSTKKY WST ON WST.WAREKEY = WT.WAREKEY AND WST.AREAKEY = WT.TOAREKY AND WST.LOCAKEY = WT.TOLOCKY AND WST.SKUMKEY = WT.SKUMKEY INNER JOIN ${userData.schema}.BADDCO BA ON WAI.ADDCOKY = BA.ADDCOKY
WT.TASKSTS != 'CANCEL' AND WRC.RCVITST != 'CANCEL'
AND WAI.WAREKEY = #{param.warekey}
AND WAI.EOASNKY = #{param.eoasnky}
AND WT.TASKOKY = #{param.taskoky}
AND WAI.ASNITST = #{param.asnitst}
AND WT.TASKSTS = #{param.tasksts}
AND WT.TASKSTS IN
#{tasksts}
GROUP BY ROWKEY, WAI.EOASNKY, WAI.EOASNIT, WAI.WAREKEY, MW.WHNAMLC, WAI.POSHPDT, WAI.INVOICE, WAI.OWNERKY, WAI.OWNRNAM, WAI.ASNITST, WAI.SKUGRKY, MG.GRPKYNM, WAI.SKUMKEY, WAI.SKUDESC, WAI.STLAYER, WAI.SKUWEIG, WAI.SKUWIDT, WAI.SKULENG, WAI.SKUTHIC, WAI.GROSSWG, WAI.GROSSWD, WAI.GROSSLN, WAI.SUOMKEY, WAI.SKUSTRD, WAI.ADDCOKY, WAI.ASNDQTY, WAI.RCHSQTY, WAI.CUSTCOD, WAI.CUSTNAM, WAI.REGIORG, MR1.RENAMLC, WAI.DEORGNM, WAI.REGIMOD, MR2.RENAMLC, WAI.DEMODNM, WAI.DEMDMAN, WAI.DEMDADR, WAI.DEMPOCD, WAI.DEMDTLN, WAI.ITEMCOD, WAI.PURCNUM, WAI.ORDERLN, WAI.STLOTNB, WAI.BTRFSTC, WAI.SKUSTAT, WAI.SHPLIMT, WAI.DELVDSR, WAI.RSNCODE, MRC.RSNCDNM, WAI.PARSNNM, WAI.COSTRKY, WAI.COSTRIT, ASNITSN, SKUSTNM, ADDCONM, TASKSTSNM, SUOMNAM, ITCODNM ORDER BY WT.TOLOCKY, WT.TOLAYER

mapper.insert:
		/* saveDoe033Wstkky */
		INSERT INTO ${userData.schema}.WSTKKY(
			STOCKKY
			, WAREKEY, AREAKEY, LOCAKEY, LOLAYER
			, LOTNMKY
			, OWNERKY, OWNRNAM, CUSTCOD, CUSTNAM, FNCUSKY
			, SKUMKEY, SKUDESC
			, SKUGRKY
			, GROSSWG, GROSSWD, GROSSLN, GROSSTH
			, SKUWEIG, SKUWIDT, SKULENG, SKUTHIC
			, BTRCATE, STLOTNB, PURCNUM, ORDERLN
			, REGIORG, DESTORG, DEORGNM, REGIMOD, DESTMOD, DEMODNM
			, DEMDMAN, DEMDADR, DEMPOCD, DEMDTLN
			, ITEMCOD, STOTQTY
			, SUOMKEY
			, ADDCOKY, BTRFSTC, STKMEMO
			, POSHPDT, POSHPTM, POSHPDY
			, SHPLIMT, DELVDSR
			, RCVDCDT
			, RCVDCTM
			, RCVDCKY, RCVDCIT
			, TASKOKY, TASKOIT
			, CREDATE, CRETIME, CREUSER
			, LMODATE, LMOTIME, LMOUSER
			, UPINFST
		)
		VALUES(
			#{item.stockky}
			, #{item.warekey}, #{item.toareky}, #{item.tolocky}, #{item.tolayer}
			, #{item.lotnmky}
			, #{item.ownerky}, #{item.ownrnam}, #{item.custcod}, #{item.custnam}, #{item.fncusky}
			, #{item.skumkey}, #{item.skudesc}
			,(
				SELECT MG.SKUGRKY
		        FROM ${userData.schema}.MGRPMA MG
		        WHERE
		        	((MG.MINLENG = 0 OR MG.MINLENG <= #{item.skuleng}) AND (MG.MAXLENG = 0 OR #{item.skuleng} < MG.MAXLENG))
		        	AND ((MG.MINWIDT = 0 OR MG.MINWIDT <= #{item.skuwidt}) AND (MG.MAXWIDT = 0 OR #{item.skuwidt} < MG.MAXWIDT))
		        	AND MG.GRUSEYN = 'Y'
        	)
			, #{item.grosswg}, #{item.grosswd}, #{item.grossln}, #{item.grossth}
			, #{item.skuweig}, #{item.skuwidt}, #{item.skuleng}, #{item.skuthic}
			, #{item.btrcate}, IFNULL(#{item.stlotnb},''), #{item.purcnum}, #{item.orderln}
			, #{item.regiorg}, IFNULL(#{item.destorg},''), #{item.deorgnm}, #{item.regimod}, IFNULL(#{item.destmod},''), #{item.demodnm}
			, #{item.demdman}, #{item.demdadr}, #{item.dempocd}, #{item.demdtln}
			, #{item.itemcod}, #{item.asndqty}
			, #{item.suomkey}
			, 
			, #{item.btrfstc}, #{item.stkmemo}
			, REPLACE(#{item.poshpdt},'-',''), REPLACE(#{item.poshptm},':',''), #{item.poshpdy}
			,CASE
			    WHEN #{item.shplimt} IS NULL OR #{item.shplimt} = '' THEN ''
			    ELSE DATE_FORMAT(#{item.shplimt}, '%Y%m%d')
			END,
			CASE
			    WHEN #{item.delvdsr} IS NULL OR #{item.delvdsr} = '' THEN ''
			    ELSE DATE_FORMAT(#{item.delvdsr}, '%Y%m%d')
			END
			, IF(#{item.rcvdcdt} IS NULL OR #{item.rcvdcdt} = '', date_format(now(), '%Y%m%d'), REPLACE(#{item.rcvdcdt}, '-', ''))
			, IF(#{item.rcvdctm} IS NULL OR #{item.rcvdctm} = '', date_format(now(), '%H%i%s'), REPLACE(#{item.rcvdctm}, ':', ''))
			, #{item.rcvdcky}, #{item.rcvdcit}
			, #{item.taskoky}, #{item.taskoit}
			, date_format(now(), '%Y%m%d')
			, date_format(now(), '%H%i%s')
			, #{userData.useract}
			, date_format(now(), '%Y%m%d')
			, date_format(now(), '%H%i%s')
			, #{userData.useract}
			, 'Y'
		)

mapper.update:
/* saveDoe033WtakitOperStart */
UPDATE ${userData.schema}.WTAKIT
	SET
		TASKSTS = #{param.tasksts},
		MVSTDAT = date_format(now(), '%Y%m%d'),
		MVSTTIM = date_format(now(), '%H%i%s'),
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = #{param.updtchk} + 1
	WHERE
		TASKOKY = #{param.taskoky}
		AND TASKOIT = #{param.taskoit}
		AND WAREKEY = #{param.warekey}
		AND UPDTCHK = #{param.updtchk}

/* saveDoe033WtakitOperCmp */
UPDATE ${userData.schema}.WTAKIT
	SET
		TASKSTS = #{param.tasksts},
		MVEDDAT = date_format(now(), '%Y%m%d'),
		MVEDTIM = date_format(now(), '%H%i%s'),
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = #{param.updtchk} + 1
	WHERE
		TASKOKY = #{param.taskoky}
		AND TASKOIT = #{param.taskoit}
		AND WAREKEY = #{param.warekey}
		AND UPDTCHK = #{param.updtchk}

mapper.select:
/* getWasnitUllockyGroup */
SELECT
	EOASNKY, WAREKEY, ULLOCKY, TOAREKY
FROM
	${userData.schema}.WASNIT
WHERE
	WAREKEY = #{param.warekey}
	AND EOASNKY = #{param.eoasnky}
GROUP BY ULLOCKY, EQUIPKY

/* selectWrcvitStatusList */
SELECT
	WR.RCVDCKY, WR.RCVDCIT, WR.WAREKEY, WR.RCVITST,
	WR.EOASNKY, WR.EOASNIT, WR.COSTRKY, WR.COSTRIT
FROM
    ${userData.schema}.WRCVIT WR
WHERE
	WR.WAREKEY = #{param.warekey}
    AND WR.RCVDCKY = #{param.rcvdcky}

    AND WR.RCVITST in

    	 	#{rcvitst}


    AND WR.RCVITST != 'CANCEL'

/* selectWrcvitRVCMPList */
SELECT
	WR.RCVDCKY, WR.RCVDCIT, WR.WAREKEY, WR.RCVITST,
	WR.EOASNKY, WR.EOASNIT, WR.COSTRKY, WR.COSTRIT
FROM
    ${userData.schema}.WRCVIT WR
WHERE
	WR.WAREKEY = #{param.warekey}
    AND WR.RCVDCKY = #{param.rcvdcky}

    AND WR.RCVITST in

    	 	#{rcvitst}

/* selectTaskWrcvhdList */ SELECT
CONCAT(WRH.RCVDCKY) AS ROWKEY,
WRH.RCVDCKY,
WRH.WAREKEY, WRH.DOCCATE, WRH.DOCTYPE, WRH.VOWNKEY, WRH.VEHICKY, WRH.VHCFNAM, WRH.DRVERNM, WRH.PASTRKY, WRH.RCVDCST, WRH.RCVRSCD, WRH.RCVRSNM, WRH.RCARSCD, WRH.RCARSNM,
MW.WHNAMLC AS WHNAMLC, MD.DOCCTNM AS DOCCTNM, MD.DOCTYNM AS DOCTYNM, MVO.VONAMLC AS VONAMLC, WTA.TASKOKY AS TASKOKY, WTA.TASKSTS AS TASKSTS, MC.COMCDTX AS RCVDCSTNM, MR1.RSNCDNM AS RCVRSCDNM, WTA.EOASNKY AS EOASNKY, WRI.PURCNUM, WRI.ORDERLN,
WRH.CREDATE, WRH.CRETIME, WRH.CREUSER, WRH.LMODATE, WRH.LMOTIME, WRH.LMOUSER, WRH.UPDTCHK FROM ${userData.schema}.WRCVHD WRH INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WRH.WAREKEY LEFT JOIN ( SELECT DISTINCT RCVDCKY, EOASNKY, RCVDCDT, SKUMKEY, PURCNUM, ORDERLN FROM ${userData.schema}.WRCVIT ) AS WRI ON WRI.RCVDCKY = WRH.RCVDCKY LEFT JOIN ( SELECT DISTINCT TASKOKY, RCVDCKY, TASKSTS, EOASNKY FROM ${userData.schema}.WTAKIT ) AS WTA ON WTA.RCVDCKY = WRH.RCVDCKY LEFT JOIN ${userData.commonSchema}.MVOWMA MVO ON MVO.VOWNKEY = WRH.VOWNKEY LEFT JOIN ${userData.commonSchema}.MVHCMA MV ON MVO.VOWNKEY = WRH.VOWNKEY AND MV.VEHICKY = WRH.VEHICKY INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WRH.RCVDCST AND MC.COMCDKY = 'RCVDCST' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WRH.WAREKEY AND MD.DOCCATE = WRH.DOCCATE AND MD.DOCTYPE = WRH.DOCTYPE LEFT JOIN ${userData.schema}.MRSCMA MR1 ON MR1.WAREKEY = WRH.WAREKEY AND MR1.DOCCATE = WRH.DOCCATE AND MR1.DOCTYPE = WRH.DOCTYPE AND MR1.RSNCODE = WRH.RCVRSCD LEFT JOIN ${userData.schema}.MRSCMA MR2 ON MR2.WAREKEY = WRH.WAREKEY AND MR2.DOCCATE = WRH.DOCCATE AND MR2.DOCTYPE = WRH.DOCTYPE AND MR2.RSNCODE = WRH.RCARSCD INNER JOIN ${userData.schema}.WASNHD WAH ON WAH.EOASNKY = WRI.EOASNKY
AND WRH.WAREKEY = #{param.warekey}
AND WRH.RCVDCKY LIKE CONCAT('%', #{param.rcvdcky}, '%')
AND WRH.VHCFNAM LIKE CONCAT('%', #{param.vhcfnam}, '%')
AND WRI.EOASNKY LIKE CONCAT('%', #{param.eoasnky}, '%')
AND WRI.PURCNUM LIKE CONCAT('%', #{param.purcnum}, '%')
AND WRI.ORDERLN IN
#{orderln}
AND WRI.ORDERLN LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND WRH.RCVDCST IN (#{param.rcvdcst})
AND WRH.RCVDCST IN
#{rcvdcst}
AND DATE_FORMAT(STR_TO_DATE(WAH.ASNDATE, '%Y%m%d'), '%Y-%m-%d') >= #{param.asndateFrom}
AND DATE_FORMAT(STR_TO_DATE(WAH.ASNDATE, '%Y%m%d'), '%Y-%m-%d') <= #{param.asndateTo}
AND WTA.TASKOKY LIKE CONCAT('%', #{param.taskoky}, '%')
AND WTA.TASKSTS = #{param.tasksts}
AND WTA.TASKSTS IN
#{tasksts}
AND WAH.ASNSTAT IN
#{asnstat}
GROUP BY
WRH.RCVDCKY,
WRH.WAREKEY, WRH.DOCCATE, WRH.DOCTYPE, WRH.VOWNKEY, WRH.VEHICKY, WRH.VHCFNAM, WRH.DRVERNM, WRH.PASTRKY, WRH.RCVDCST, WRH.RCVRSCD, WRH.RCVRSNM, WRH.RCARSCD, WRH.RCARSNM,
WTA.TASKOKY,
WRH.CREDATE, WRH.CRETIME, WRH.CREUSER, WRH.LMODATE, WRH.LMOTIME, WRH.LMOUSER, WRH.UPDTCHK HAVING WTA.TASKSTS != 'CANCEL' ORDER BY RCVDCKY DESC, TASKOKY DESC, EOASNKY DESC

/* selectDoe034TaskWrcvhdList */ SELECT CONCAT(WRH.RCVDCKY) AS ROWKEY, WRH.RCVDCKY, WRH.WAREKEY, WRH.DOCCATE, WRH.DOCTYPE, WRH.VOWNKEY, WRH.VEHICKY, WRH.VHCFNAM, WRH.DRVERNM, WRH.PASTRKY, WRH.RCVDCST, IF(WRH.RCVDCST = 'ACANCEL', WRH.RCARSCD, WRH.RCVRSCD) as RCARSCD, IF(WRH.RCVDCST = 'ACANCEL', WRH.RCVRSNM, WRH.RCVRSNM) as RCVRSNM, WTA.EQUIPKY, MEQ.EQUINAM, WRH.RCARSNM, IFNULL(WTAK.STATCNT, 0) AS STATCNT, MW.WHNAMLC AS WHNAMLC, MD.DOCCTNM AS DOCCTNM, MD.DOCTYNM AS DOCTYNM, MVO.VONAMLC AS VONAMLC, WTA.TASKOKY AS TASKOKY, WTA.TASKSTS AS TASKSTS, MC.COMCDTX AS RCVDCSTNM, IF(WRH.RCVDCST = 'ACANCEL', MR2.RSNCDNM, MR1.RSNCDNM) AS RCVRSCDNM, WTA.EOASNKY AS EOASNKY, MC2.COMCDTX AS TASKSTSNM, WRH.CREDATE, WRH.CRETIME, WRH.CREUSER, WRH.LMODATE, WRH.LMOTIME, WRH.LMOUSER, WRH.UPDTCHK FROM ${userData.schema}.WTAKIT WTA INNER JOIN ${userData.schema}.WRCVHD WRH ON WRH.WAREKEY = WTA.WAREKEY AND WRH.RCVDCKY = WTA.RCVDCKY INNER JOIN ${userData.schema}.WRCVIT WRI ON WRI.WAREKEY = WTA.WAREKEY AND WRI.RCVDCKY = WTA.RCVDCKY AND WRI.RCVDCIT = WTA.RCVDCIT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WRH.WAREKEY INNER JOIN ${userData.commonSchema}.MVOWMA MVO ON MVO.VOWNKEY = WRH.VOWNKEY INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MVO.VOWNKEY = WRH.VOWNKEY AND MV.VEHICKY = WRH.VEHICKY INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WRH.RCVDCST AND MC.COMCDKY = 'RCVDCST' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WRH.WAREKEY AND MD.DOCCATE = WRH.DOCCATE AND MD.DOCTYPE = WRH.DOCTYPE LEFT JOIN ${userData.schema}.MRSCMA MR1 ON MR1.WAREKEY = WRH.WAREKEY AND MR1.DOCCATE = WRH.DOCCATE AND MR1.DOCTYPE = WRH.DOCTYPE AND MR1.RSNCODE = WRH.RCVRSCD LEFT JOIN ${userData.schema}.MRSCMA MR2 ON MR2.WAREKEY = WRH.WAREKEY AND MR2.DOCCATE = WRH.DOCCATE AND MR2.DOCTYPE = WRH.DOCTYPE AND MR2.RSNCODE = WRH.RCARSCD INNER JOIN ${userData.schema}.MCODEM MC2 ON MC2.COMCDVL = WTA.TASKSTS AND MC2.COMCDKY = 'TASKSTS' AND MC2.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MEQUMA MEQ ON MEQ.WAREKEY = WTA.WAREKEY AND MEQ.EQUIPKY = WTA.EQUIPKY LEFT JOIN ( SELECT COUNT(1) as STATCNT, EOASNKY, RCVDCKY, TASKSTS FROM ${userData.schema}.WTAKIT WHERE DOCCATE = '400' AND TASKSTS IN ('NEW', 'OPERSTR', 'TASKCMP', 'CMP') GROUP BY EOASNKY, RCVDCKY, TASKSTS ) as WTAK ON WTAK.EOASNKY = WTA.EOASNKY AND WTAK.RCVDCKY = WTA.RCVDCKY
AND WRH.WAREKEY = #{param.warekey}
AND WRH.RCVDCKY LIKE CONCAT('%', #{param.rcvdcky}, '%')
AND WRH.VHCFNAM LIKE CONCAT('%', #{param.vhcfnam}, '%')
AND WRI.EOASNKY LIKE CONCAT('%', #{param.eoasnky}, '%')
AND WRI.PURCNUM LIKE CONCAT('%', #{param.purcnum}, '%')
AND WRI.SKUMKEY IN
#{skumkey}
AND WRI.SKUMKEY LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND WRI.ORDERLN IN
#{orderln}
AND WRI.ORDERLN LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND WRH.RCVDCST IN (#{param.rcvdcst})
AND WRH.RCVDCST IN
#{rcvdcst}
AND DATE_FORMAT(STR_TO_DATE(WRI.RCVDCDT, '%Y%m%d'), '%Y-%m-%d') >= #{param.rcvdcdtFrom}
AND DATE_FORMAT(STR_TO_DATE(WRI.RCVDCDT, '%Y%m%d'), '%Y-%m-%d') <= #{param.rcvdcdtTo}
AND WTA.TASKOKY = LIKE CONCAT('%', #{param.taskoky}, '%')
AND WTA.TASKSTS = #{param.tasksts}
AND WTA.TASKSTS IN
#{tasksts}
GROUP BY WRH.RCVDCKY, WRH.WAREKEY, WRH.DOCCATE, WRH.DOCTYPE, WRH.VOWNKEY, WRH.VEHICKY, WRH.VHCFNAM, WRH.DRVERNM, WRH.PASTRKY, WRH.RCVDCST, WRH.RCVRSCD, WRH.RCVRSNM, WRH.RCARSCD, WRH.RCARSNM, WTA.TASKOKY, WRH.CREDATE, WRH.CRETIME, WRH.CREUSER, WRH.LMODATE, WRH.LMOTIME, WRH.LMOUSER, WRH.UPDTCHK ORDER BY RCVDCKY DESC, TASKOKY DESC, EOASNKY DESC

/* selectTaskWrcvitList */ SELECT CONCAT(WRI.RCVDCKY, WRI.RCVDCIT) AS ROWKEY , WRI.RCVDCKY, WRI.RCVDCIT, WRI.POSHPDT, WRI.INVOICE , WRI.WAREKEY, WRI.OWNERKY, WRI.OWNRNAM, WRI.RCVITST , MC.COMCDTX as RCVITNM, WRI.CUSTCOD, WRI.CUSTNAM, WRI.SKUGRKY , WRI.SKUMKEY, WRI.SKUDESC, WRI.SKULENG, WRI.SKUWIDT , WRI.SKUTHIC, WRI.SKUWEIG, WRI.GROSSWD, WRI.GROSSLN , WRI.GROSSWG, WRI.STLAYER, WRI.REGIORG, WRI.DEORGNM , WRI.REGIMOD, WRI.DEMODNM, WRI.ULLOCKY, ML1.LOCANAM AS ULLOCNM , WRI.ADDCOKY, WRI.SKUSTRD, WRI.RESTKYN, WTA.TOAREKY , MA.AREANAM AS TOARENM, WTA.TOLOCKY, ML2.LOCANAM AS TOLOCNM, WTA.TOLAYER , WRI.ITEMCOD, WRI.STLOTNB, WRI.PURCNUM, WRI.ORDERLN , WRI.RCVDCDT, WRI.RCVDCTM, WRI.ASNDQTY, WRI.RCHSQTY , WRI.SUOMKEY, WRI.SHPLIMT, WRI.DELVDSR, WRI.BTRFSTC , WRI.EOASNKY, WRI.EOASNIT, WRI.COSTRKY, WRI.COSTRIT , WRI.RCARSCD, WRI.RCARSNM, WRI.BTRCATE, WRI.GROSSTH , WRI.SERINUM, WRI.SAVEPOS, WRI.SCHDATE, WRI.MIXLOAD , WRI.YARDTRG, WRI.INBDATE, WRI.INBVHNM, WRI.OUBVHNM , WRI.SHPDRNM, WRI.PRSALDT, WRI.CMPDATE, WRI.SHPPERS , WRI.OUBDATE, WRI.PREPRDE, WRI.ARVDATE, WRI.SHPODAT , WRI.TRSODAT, WRI.INDIMET, WRI.OUTDIMT, WRI.DESTTRG , WRH.DOCCATE, WRH.DOCTYPE, WTA.TASKOKY, WTA.TASKSTS , MW.WHNAMLC, MD.DOCCTNM, MD.DOCTYNM, MR2.RSNCDNM AS RCARSNM , MG.GRPKYNM, MRE1.RENAMLC AS REORGNM, MRE2.RENAMLC AS REMODNM , BC.BTRCNAM, WRI.CREDATE, WRI.CRETIME, WRI.CREUSER , WRI.LMODATE, WRI.LMOTIME, WRI.LMOUSER, WRI.UPDTCHK , (SELECT count(1) - WRI.STLAYER + 1 FROM ${userData.schema}.WRCVIT WHERE WAREKEY = #{param.warekey} AND RCVDCKY = #{param.rcvdcky}) AS VSLAYER , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ITEMCOD' AND COMCDVL = WRI.ITEMCOD AND COUSEYN = 'Y') AS ITCODNM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'SUOMKEY' AND COMCDVL = WRI.SUOMKEY AND COUSEYN = 'Y') AS SUOMNAM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'TASKSTS' AND COMCDVL = WTA.TASKSTS AND COUSEYN = 'Y') AS TASKSTSNM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = BA.ADDSIKY AND COUSEYN = 'Y') AS ADDCONM FROM ${userData.schema}.WRCVIT WRI INNER JOIN ${userData.schema}.WRCVHD WRH ON WRH.WAREKEY = WRI.WAREKEY AND WRH.RCVDCKY = WRI.RCVDCKY INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WRI.WAREKEY INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WRI.WAREKEY AND ML1.LOCAKEY = WRI.ULLOCKY INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = WRI.SKUGRKY INNER JOIN ${userData.schema}.BTRCAT BC ON BC.BTRCATE = WRI.BTRCATE INNER JOIN ${userData.schema}.BADDCO BA ON WRI.ADDCOKY = BA.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDKY = 'RCVITST' AND MC.COMCDVL = WRI.RCVITST AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WRI.WAREKEY AND MD.DOCCATE = WRI.DOCCATE AND MD.DOCTYPE = WRI.DOCTYPE INNER JOIN ${userData.schema}.MREGMA MRE1 ON MRE1.REGIKEY = WRI.REGIORG INNER JOIN ${userData.schema}.MREGMA MRE2 ON MRE2.REGIKEY = WRI.REGIMOD INNER JOIN ( SELECT DISTINCT TASKOKY, RCVDCKY, RCVDCIT, TASKSTS, EOASNKY , WAREKEY, TOAREKY, TOLOCKY, TOLAYER FROM ${userData.schema}.WTAKIT
AND WAREKEY = #{param.warekey}
AND TASKOKY = #{param.taskoky}
) AS WTA ON WTA.WAREKEY = WRI.WAREKEY AND WTA.RCVDCKY = WRI.RCVDCKY AND WTA.RCVDCIT = WRI.RCVDCIT INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WTA.WAREKEY AND MA.AREAKEY = WTA.TOAREKY INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WTA.WAREKEY AND ML2.AREAKEY = WTA.TOAREKY AND ML2.LOCAKEY = WTA.TOLOCKY INNER JOIN ${userData.schema}.MRSCMA MR1 ON MR1.WAREKEY = WRI.WAREKEY AND MR1.DOCCATE = WRI.DOCCATE AND MR1.DOCTYPE = WRI.DOCTYPE AND MR1.RSNCODE = WRI.RCVRSCD LEFT JOIN ${userData.schema}.MRSCMA MR2 ON MR2.WAREKEY = WRI.WAREKEY AND MR2.DOCCATE = WRI.DOCCATE AND MR2.DOCTYPE = WRI.DOCTYPE AND MR2.RSNCODE = WRI.RCARSCD
AND WRI.WAREKEY = #{param.warekey}
AND WRI.EOASNKY = #{param.eoasnky}
AND WRI.RCVDCKY = #{param.rcvdcky}
AND WTA.TASKOKY = #{param.taskoky}
ORDER BY WRI.STLAYER DESC

mapper.update:
/* updateWrcvhdStatus */
UPDATE ${userData.schema}.WRCVHD
SET
	RCVDCST = #{status},

		RCARSCD= #{param.rcarscd},


		RCARSNM = #{param.rcarsnm},

	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract}
WHERE
	WAREKEY = #{param.warekey}
	AND RCVDCKY = #{param.rcvdcky}

/* updateWrcvitStatus */

UPDATE ${userData.schema}.WRCVIT
SET
	RCVITST = #{status},

	RCHSQTY = #{data.rchsqty},


		RCVRSCD= #{data.rcarscd},


		RCVRSNM = #{data.rcarsnm},

	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract}
WHERE
	WAREKEY = #{data.warekey}
	AND RCVDCKY = #{data.rcvdcky}

	AND RCVDCIT = #{data.rcvdcit}


	AND RCVITST != 'CANCEL'

mapper.insert:
INSERT INTO ${userInfo.schema}.TPLNIT ( WAREKEY, VHPLNKY, VHPLNIT, CUSTCOD , CUSTNAM, TPISTAT, OWNERKY, OWNRNAM , SKUMKEY, SKUDESC, TRITQTY, REGIORG , REGIMOD, DESTORG, DEORGNM, DESTMOD , DEMODNM, DEMDMAN, DEMPOCD, DEMDADR , DEMDTLN, ITEMCOD, SKUGRKY, SKUTHIC , SKUWIDT, SKULENG, SKUWEIG, GROSSWD , GROSSLN, GROSSTH, STKMEMO, GROSSWG , ADDCOKY, BTRCATE, PURCNUM, ORDERLN , SUOMKEY, EOASNKY, EOASNIT, POSHPDT , POSHPTM, POSHPDY, SHPLIMT, DELVDSR, BTRFSTC , TRNCPDT, TRNCPTM , PLNSIZE, BILDATE , CREUSER, LMODATE, LMOTIME, LMOUSER ) SELECT WA.WAREKEY, #{param.vhplnky}, ${userInfo.schema}.FN_TM_VHPLNIT(#{param.vhplnky}), WI.CUSTCOD , WI.CUSTNAM, 'ARRIVE', WI.OWNERKY, WI.OWNRNAM , WI.SKUMKEY, WI.SKUDESC, WI.ASNDQTY, WI.REGIORG , WI.REGIMOD, WI.DESTORG, WI.DEORGNM, WI.DESTMOD , WI.DEMODNM, WI.DEMDMAN, WI.DEMPOCD, WI.DEMDADR , WI.DEMDTLN, WI.ITEMCOD, WI.SKUGRKY, WI.SKUTHIC , WI.SKUWIDT, WI.SKULENG, WI.SKUWEIG, WI.GROSSWD , WI.GROSSLN, WI.GROSSTH, WI.STKMEMO, WI.GROSSWG , WI.ADDCOKY, WI.BTRCATE, WI.PURCNUM, WI.ORDERLN , WI.SUOMKEY, WI.EOASNKY, WI.EOASNIT, WI.POSHPDT , WI.POSHPTM, WI.POSHPDY, WI.SHPLIMT, WI.DELVDSR, WI.BTRFSTC , TO_CHAR(CURRENT_TIMESTAMP(), 'YYYYMMDD'), TO_CHAR(CURRENT_TIMESTAMP(),'HH24MISS') , WI.SKUGRKY, TO_CHAR(CURRENT_TIMESTAMP(), 'YYYYMMDD') , #{userInfo.useract}, TO_CHAR(CURRENT_TIMESTAMP(), 'YYYYMMDD'), TO_CHAR(CURRENT_TIMESTAMP(),'HH24MISS'), #{userInfo.useract} FROM ${userInfo.schema}.WASNHD WA INNER JOIN ${userInfo.schema}.WASNIT WI ON WA.EOASNKY = WI.EOASNKY AND WA.WAREKEY = WI.WAREKEY
AND WA.WAREKEY = #{param.warekey} AND WA.EOASNKY = #{param.eoasnky}
ORDER BY WI.EOASNIT

