/* getDoe024AsnItemListStlayer */
SELECT
	WAREKEY, EOASNKY, EOASNIT, SKUMKEY
	, STLAYER, UPDTCHK
FROM
	${userInfo.schema}.WASNIT
WHERE
	WAREKEY = #{param.warekey}
	AND EOASNKY = #{param.eoasnky}
ORDER BY STLAYER

mapper.update:
/* updateDoe024AsnItemStlayer */
UPDATE ${userInfo.schema}.WASNIT
	SET STLAYER = #{param.stlayer},
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userInfo.useract},
		UPDTCHK = #{param.updtchk} + 1
	WHERE
		WAREKEY = #{param.warekey}
		AND EOASNKY = #{param.eoasnky}
		AND EOASNIT = #{param.eoasnit}
		AND SKUMKEY = #{param.skumkey}
		AND UPDTCHK = #{param.updtchk}

