/* isSameLocationAndLayer */
SELECT
	STOCKKY, SKUMKEY
FROM
	${userData.schema}.WSTKKY
WHERE
	AREAKEY = #{param.toareky}
	AND LOCAKEY = #{param.tolocky}
	AND LOLAYER = #{param.tolayer}
LIMIT 1

/* getAsnTaskoky */
SELECT
	TASKOKY, TASKOIT
FROM
	${userData.schema}.WTAKIT
WHERE
	EOASNKY = #{param.eoasnky}
	AND EOASNIT = #{param.eoasnit}

mapper.update:
/* updateWtakitStockky */
UPDATE ${userData.schema}.WTAKIT
	SET LOTNMKY = #{param.lotnmky},
		STOCKKY = #{param.stockky},
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract}
	WHERE
		TASKOKY = #{param.taskoky}
		AND TASKOIT = #{param.taskoit}

mapper.select:
/* getFromLocationAndLayerStock */
SELECT
	STOCKKY, WAREKEY, SKUMKEY, AREAKEY, LOCAKEY, LOLAYER
	, UPDTCHK
FROM
	${userData.schema}.WSTKKY
WHERE
	AREAKEY = #{param.toareky}
	AND LOCAKEY = #{param.tolocky}
	AND LOLAYER >= #{param.tolayer}
ORDER BY LOLAYER ASC

mapper.update:
/* updateLayerStockShift */
UPDATE ${userData.schema}.WSTKKY
SET	LOLAYER = #{param.lolayer},
	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract},
	UPDTCHK = #{param.updtchk} + 1
WHERE
	WAREKEY = #{param.warekey}
	AND STOCKKY = #{param.stockky}
	AND AREAKEY = #{param.areakey}
	AND LOCAKEY = #{param.locakey}
	AND UPDTCHK = #{param.updtchk}

mapper.select:
/* getPhyCreateLocationStockInfo */
SELECT
	STOCKKY, WAREKEY, SKUMKEY, AREAKEY, LOCAKEY, LOLAYER as STLAYER
	, 'N' as RMSTKYN, 'N' as RETUNYN
	, DATE_FORMAT(now(), '%y-%m-%d %H:%i:%s') as PHYDTTM
FROM
	${userData.schema}.WSTKKY
WHERE
	WAREKEY = #{param.warekey}
	AND AREAKEY = #{param.toareky}
	AND LOCAKEY = #{param.tolocky}
ORDER BY LOLAYER ASC
